import{_ as s,C as i,o as h,c as d,ah as o,j as a,a as t,E as n}from"./chunks/framework.C8Zd3T50.js";const g=JSON.parse('{"title":"Glossary","description":"A comprehensive glossary of terms used in the os384 ecosystem","frontmatter":{"title":"Glossary","description":"A comprehensive glossary of terms used in the os384 ecosystem"},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md"}'),l={name:"glossary.md"};function c(p,e,f,u,m,y){const r=i("ApiLink");return h(),d("div",null,[e[71]||(e[71]=o('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>This glossary provides definitions for key terms and concepts used throughout the os384 ecosystem. Terms are organized alphabetically for easy reference.</p><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><h3 id="addressable-worker" tabindex="-1">addressable worker <a class="header-anchor" href="#addressable-worker" aria-label="Permalink to &quot;addressable worker&quot;">​</a></h3><p>An edge computing worker that has a persistent global identity — all requests for a specific addressable worker are routed to the same instance, wherever it happens to be running in the infrastructure. Because it is &quot;addressable,&quot; it can maintain local state (<a href="#kv_local">KV_local</a>) and support long-lived <a href="#channel-server">WebSocket</a> connections for real-time communication. Contrast with <a href="#non-addressable-worker">non-addressable worker</a>.</p><p>In os384: each <a href="#channel">Channel</a> is backed by an addressable worker (a <a href="#durable-object">Durable Object</a> in the Cloudflare reference implementation). This is why channel operations have strong consistency guarantees — all synchronous calls for a given channel route to one instance.</p><p><em>Related: <a href="#non-addressable-worker">non-addressable worker</a>, <a href="#durable-object">Durable Object</a>, <a href="#kv_local">KV_local</a>, <a href="#channel">Channel</a></em></p><p><em>Read more: <a href="/BhoW6b/architecture.html">architecture</a></em></p><hr><h3 id="aes-256-gcm" tabindex="-1">AES-256-GCM <a class="header-anchor" href="#aes-256-gcm" aria-label="Permalink to &quot;AES-256-GCM&quot;">​</a></h3><p>AES-256-GCM (Advanced Encryption Standard, 256-bit key, Galois/Counter Mode) is a standard <em>authenticated</em> encryption algorithm. &quot;Authenticated&quot; means it both encrypts data and detects any tampering — if the ciphertext has been modified, decryption fails rather than silently producing garbage. The 256-bit key makes brute-force attacks computationally infeasible for the foreseeable future.</p><p>In os384: AES-256-GCM is the symmetric encryption used for all stored <a href="#object">objects</a> and for group <a href="#channel">Channel</a> messages (<code>Protocol_AES_GCM_256</code>). The encryption key for a shard is derived from the content&#39;s own hash using <a href="#pbkdf2">PBKDF2</a>.</p><p><em>Related: <a href="#pbkdf2">PBKDF2</a>, <a href="#nonce">nonce</a>, <a href="#iv">iv</a>, <a href="#salt">salt</a>, <a href="#protocol">protocol</a></em></p><hr><h3 id="appmain" tabindex="-1">AppMain <a class="header-anchor" href="#appmain" aria-label="Permalink to &quot;AppMain&quot;">​</a></h3><p>The bootstrap class for os384 applications. An app built with <code>AppMain</code> declares a manifest (<code>384.manifest.json</code>) specifying its entry point, dependencies, and resource channels. When the <a href="#loader">Loader</a> launches an app, <code>AppMain</code> handles initialization: locating the ledger channel, verifying storage, and setting up the app&#39;s runtime environment.</p><p>During local development without the Loader, <code>AppMain.init()</code> supports a <a href="#shadow-manifest">shadow manifest</a> (<code>.384.manifest.json</code> dotfile) that takes priority over the published manifest, allowing iterative development without redeployment.</p><p><em>Related: <a href="#loader">Loader</a>, <a href="#manifest">manifest</a>, <a href="#shadow-manifest">shadow manifest</a>, <a href="#budget-channel">budget channel</a>, <a href="#channel">Channel</a></em></p>',18)),a("p",null,[a("em",null,[e[0]||(e[0]=t("API: ",-1)),n(r,{type:"class",name:"AppMain"})])]),e[72]||(e[72]=o('<hr><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><h3 id="base32" tabindex="-1">base32 <a class="header-anchor" href="#base32" aria-label="Permalink to &quot;base32&quot;">​</a></h3><p>A text encoding that uses a 32-character alphabet. os384 uses Crockford&#39;s Base32 variant (digits 0–9 plus uppercase consonants, excluding visually ambiguous characters like I, L, O, U) for the <a href="#channel-id">Channel ID</a> hash representation (<code>hashB32</code>) and for <a href="/BhoW6b/glossary.html#page-channel-page">channel page</a> URL prefixes. The limited character set makes these identifiers easy to read aloud, type manually, and embed in URLs without case sensitivity issues.</p><p><em>Related: <a href="#base62">base62</a>, <a href="#channel-id">Channel ID</a>, <a href="#strongpin">strongpin</a>, <a href="#page-channel-page">page</a></em></p><hr><h3 id="base62" tabindex="-1">base62 <a class="header-anchor" href="#base62" aria-label="Permalink to &quot;base62&quot;">​</a></h3><p>A text encoding that uses only alphanumeric characters (A–Z, a–z, 0–9) — 62 characters total. Unlike base64, which requires two additional symbols (typically <code>+</code> and <code>/</code>), base62 can be embedded anywhere an alphanumeric string is expected — URLs, filenames, database keys, log entries — without any escaping or quoting.</p>',8)),a("p",null,[e[1]||(e[1]=t("In os384: base62 is the universal wire format for all external identifiers: ",-1)),e[2]||(e[2]=a("a",{href:"#channel-id"},"Channel IDs",-1)),e[3]||(e[3]=t(", user IDs, object handles, and keys. Implemented in the reference library at ",-1)),e[4]||(e[4]=a("a",{href:"https://github.com/petersmagnusson/base62",target:"_blank",rel:"noreferrer"},"github.com/petersmagnusson/base62",-1)),e[5]||(e[5]=t(", exported as ",-1)),n(r,{type:"function",name:"arrayBufferToBase62"}),e[6]||(e[6]=t(" and ",-1)),n(r,{type:"function",name:"base62ToArrayBuffer"}),e[7]||(e[7]=t(".",-1))]),e[73]||(e[73]=o('<p><em>Related: <a href="#channel-id">Channel ID</a>, <a href="#fn">FN</a>, <a href="#owner-key">Owner Key</a></em></p><hr><h3 id="budd" tabindex="-1">budd <a class="header-anchor" href="#budd" aria-label="Permalink to &quot;budd&quot;">​</a></h3><p>To &quot;budd&quot; a channel is to spin off a new <a href="#channel">Channel</a> from an existing one, optionally transferring some or all of the parent channel&#39;s <a href="#storage-budget">storage budget</a> to the new one. A budded channel inherits nothing from the parent&#39;s messages or access control — it is a fresh, independent channel. The operation also covers transferring budget between existing channels without creating a new one.</p><p>In os384: budding is the primary mechanism for allocating storage. You start with a channel that has budget (typically seeded from a <a href="#storage-token">storage token</a>), then budd from it to create the channels your app actually uses.</p><p><em>Related: <a href="#storage-budget">Storage Budget</a>, <a href="#storage-token">storage token</a>, <a href="#channel">Channel</a>, <a href="#budget-channel">budget channel</a></em></p>',6)),a("p",null,[a("em",null,[e[8]||(e[8]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"budd"})])]),e[74]||(e[74]=o('<hr><h3 id="bootstrap" tabindex="-1">bootstrap <a class="header-anchor" href="#bootstrap" aria-label="Permalink to &quot;bootstrap&quot;">​</a></h3><p>The one-time operation of provisioning a <a href="#storage-token">storage token</a> directly into the <a href="#channel-server">Channel Server&#39;s</a> KV store, establishing the initial storage budget from which all subsequent channel creation flows. Distinct from drawing a token from an existing funded channel (which requires a channel that already has budget).</p><p>In os384: bootstrapping requires server ownership — either wrangler credentials (for direct KV writes) or admin access (for the Docker stack). The result is a <code>LEDGER_NAMESPACE</code> KV entry. Once the token is in KV, the companion step is to consume it via <code>SB.create(token)</code> (see the <code>04.01</code> regression test) to produce a <a href="#budget-channel">budget channel</a>.</p><p>Three bootstrap paths exist for local dev:</p><ul><li><strong>CLI (wrangler directly)</strong> — <code>wrangler kv key put --binding=LEDGER_NAMESPACE ...</code></li><li><strong><code>bootstrap.token.ts</code></strong> — Deno CLI wrapper around the same wrangler command</li><li><strong>Docker admin</strong> — <code>curl http://localhost:3849/refresh</code> seeds the canonical dev token automatically</li></ul><p><em>Related: <a href="#storage-token">storage token</a>, <a href="#budget-channel">budget channel</a>, <a href="#ledger_key">LEDGER_KEY</a>, <a href="#budd">budd</a></em></p><p><em>Read more: <a href="/BhoW6b/dev/local-stack.html">dev/local-stack</a></em></p><hr><h3 id="budget-channel" tabindex="-1">budget channel <a class="header-anchor" href="#budget-channel" aria-label="Permalink to &quot;budget channel&quot;">​</a></h3><p>An informal term for a <a href="#channel">Channel</a> used primarily or exclusively as a source of <a href="#storage-budget">storage budget</a> rather than for communication — often the root of a tree of <a href="#budd">budded</a> channels. Not a distinct type in the code; just a usage pattern. Typically paired with a <a href="#ledger-channel">ledger channel</a> so that operational bookkeeping and storage budget are managed independently.</p><p><em>Related: <a href="#ledger-channel">ledger channel</a>, <a href="#budd">budd</a>, <a href="#storage-budget">Storage Budget</a>, <a href="#channel">Channel</a>, <a href="#bootstrap">bootstrap</a></em></p><hr><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><h3 id="capacity" tabindex="-1">capacity <a class="header-anchor" href="#capacity" aria-label="Permalink to &quot;capacity&quot;">​</a></h3><p>The maximum number of <a href="#visitor">Visitor</a> members allowed in a <a href="#channel">Channel</a> at one time. Set by the channel owner via <code>channel.setCapacity(n)</code>. Once reached, <code>acceptVisitor()</code> will fail until the owner raises the limit or existing members leave. Capacity is one of the fields returned in <a href="#channel-handle">ChannelAdminData</a> (owner-only).</p><p>In os384: capacity is a soft policy — the default is permissive. Most apps set a meaningful capacity as part of their access-control logic (e.g., a 1-on-1 chat channel has capacity 1).</p><p><em>Related: <a href="#visitor">Visitor</a>, <a href="#owner">Owner</a>, <a href="#restricted">Restricted</a>, <a href="#locked">locked</a></em></p>',18)),a("p",null,[a("em",null,[e[9]||(e[9]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"setCapacity"})])]),e[75]||(e[75]=o('<hr><h3 id="channel" tabindex="-1">Channel <a class="header-anchor" href="#channel" aria-label="Permalink to &quot;Channel&quot;">​</a></h3><p>The fundamental communication and capability primitive of os384. A Channel is a globally unique, durable, owner-controlled endpoint — conceptually analogous to a capability-bearing port in systems like Mach/Chorus, but persistent and cryptographically owned. Every channel has a unique <a href="#channel-id">Channel ID</a> permanently derived from its owner&#39;s <a href="#p-384">P-384</a> private key, meaning the channel&#39;s identity and proof of ownership are mathematically inseparable.</p><p>Unlike a typical network socket, a Channel is not ephemeral: messages are stored permanently by default (see <a href="#ttl">TTL</a>), and the channel itself persists indefinitely. At runtime it is backed by an <a href="#addressable-worker">addressable worker</a>, so all operations on a given channel are serialized through one instance — enabling strong consistency without a central database.</p><p>A critical design property: <strong>shards have no metadata whatsoever</strong>. All context about stored objects — what they are, who they belong to, how to decrypt them — must travel as channel messages. The channel message log is therefore the metadata layer for the entire storage system. Conversely, the channel&#39;s own message history eventually migrates <em>into</em> shard storage via the <a href="#deep-history">deep history</a> mechanism, though the resulting shards have no knowledge of their origin.</p><p>Channels are the substrate on which all P2P communication in os384 apps is built. They also carry <a href="#storage-budget">storage budget</a>, expose typed data via <a href="#page">Pages</a>, and can be restricted to owner-approved <a href="#visitor">Visitors</a> only. New channels are created from existing ones via <a href="#budd">budd</a>.</p><p><em>Related: <a href="#channel-id">Channel ID</a>, <a href="#owner">Owner</a>, <a href="#owner-key">Owner Key</a>, <a href="#shard">Shard</a>, <a href="#budd">budd</a>, <a href="#addressable-worker">addressable worker</a>, <a href="#deep-history">deep history</a></em></p>',7)),a("p",null,[e[11]||(e[11]=a("em",null,[t("Read more: "),a("a",{href:"/BhoW6b/channels.html"},"channels")],-1)),e[12]||(e[12]=t(" | ",-1)),a("em",null,[e[10]||(e[10]=t("API: ",-1)),n(r,{type:"class",name:"Channel"})])]),e[76]||(e[76]=o('<hr><h3 id="channel-id" tabindex="-1">Channel ID <a class="header-anchor" href="#channel-id" aria-label="Permalink to &quot;Channel ID&quot;">​</a></h3><p>The globally unique 43-character <a href="#base62">base62</a> string that identifies a channel. It is deterministically derived from the channel owner&#39;s <a href="#p-384">P-384</a> public key as a SHA-384 hash, which means: (1) it cannot be forged without the corresponding private key; (2) it requires no central registry — the owner generates it offline; (3) knowing a Channel ID tells you nothing useful without the matching key material.</p><p>In the code and API, this is always <code>ChannelId</code> (a type alias for <code>SB384Hash</code>). Some documentation also uses &quot;Channel Name&quot; — these are the same thing.</p><p><em>Related: <a href="#channel">Channel</a>, <a href="#owner-key">Owner Key</a>, <a href="#owner-key">SB384</a>, <a href="#base62">base62</a></em></p>',5)),a("p",null,[a("em",null,[e[13]||(e[13]=t("API: ",-1)),n(r,{type:"class",name:"SB384",method:"userId"}),e[14]||(e[14]=t(", ",-1)),n(r,{type:"class",name:"SB384",method:"ownerChannelId"})])]),e[77]||(e[77]=o('<hr><h3 id="channel-handle" tabindex="-1">channel handle <a class="header-anchor" href="#channel-handle" aria-label="Permalink to &quot;channel handle&quot;">​</a></h3><p>A portable, self-contained description of a channel carrying enough information to connect to and operate it. At minimum it contains the user&#39;s private key; optionally includes the <a href="#channel-id">Channel ID</a>, channel server URL, and cached server-side channel data. Possessing a channel handle with a private key is equivalent to possessing the capability to act as owner of that channel — the handle <em>is</em> the capability token.</p><p><em>Related: <a href="#channel">Channel</a>, <a href="#channel-id">Channel ID</a>, <a href="#owner-key">Owner Key</a></em></p>',4)),a("p",null,[a("em",null,[e[15]||(e[15]=t("API: ",-1)),n(r,{type:"interface",name:"ChannelHandle"})])]),e[78]||(e[78]=o('<hr><h3 id="channel-server" tabindex="-1">Channel Server <a class="header-anchor" href="#channel-server" aria-label="Permalink to &quot;Channel Server&quot;">​</a></h3><p>The edge server (or cluster of servers) that hosts <a href="#channel">Channels</a>. Responsible for message routing, <a href="#channel-server">WebSocket</a> connections, access control (visitor admission, channel restriction), storage budget enforcement, and channel metadata. In the current implementation, a single service handles both channel and storage operations, though they remain architecturally distinct. Channel Servers can be self-hosted.</p><p><em>Related: <a href="#channel">Channel</a>, <a href="#addressable-worker">addressable worker</a>, <a href="#storage-server">Storage Server</a>, <a href="#personal-channel-server">Personal Channel Server</a></em></p><p><em>Read more: <a href="/BhoW6b/dev/local-stack.html">dev/local-stack</a></em></p><hr><h3 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h3><p>The command-line interface tools for administering os384 channels and servers. Used for tasks like creating channels, sending messages, managing storage tokens, and configuring server keys. Environment variables (<code>OS384_CHANNEL_SERVER</code>, <code>OS384_STORAGE_SERVER</code>, <code>OS384_BUDGET_KEY</code>, <code>OS384_LEDGER_KEY</code>) configure which servers the CLI targets.</p><p><em>Related: <a href="#personal-channel-server">Personal Channel Server</a>, <a href="#storage-token">storage token</a>, <a href="#ledger_key">LEDGER_KEY</a></em></p><p><em>Read more: <a href="/BhoW6b/cli.html">cli</a></em></p><hr><h3 id="content-addressing" tabindex="-1">content addressing <a class="header-anchor" href="#content-addressing" aria-label="Permalink to &quot;content addressing&quot;">​</a></h3><p>A storage scheme where an object&#39;s identity (its address) is derived from a cryptographic hash of its content. Content addressing has three important properties: (1) identical content always produces the same address, enabling <a href="#deduplication">deduplication</a> without comparing raw data; (2) any client can verify downloaded data by re-hashing it and comparing to the address; (3) addresses are server-independent — the same shard has the same ID on every storage server in the world, enabling <a href="#mirror">mirrors</a> and cache servers without coordination.</p><p>In os384: all <a href="#shard">Shards</a> are content-addressed. The storage ID is derived from the encrypted form of the data (see <a href="#fn-full-name">FN</a>). Contrast with location-based addressing (URLs), where the same content can sit at different addresses on different servers.</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#fn-full-name">FN</a>, <a href="#deduplication">deduplication</a>, <a href="#verification">verification</a></em></p><hr><h3 id="cryptobiosis" tabindex="-1">cryptobiosis <a class="header-anchor" href="#cryptobiosis" aria-label="Permalink to &quot;cryptobiosis&quot;">​</a></h3>',17)),a("p",null,[e[16]||(e[16]=t("The dormant state a ",-1)),e[17]||(e[17]=a("a",{href:"#channel"},"Channel",-1)),e[18]||(e[18]=t(" enters when it runs out of ",-1)),e[19]||(e[19]=a("a",{href:"#storage-budget"},"storage budget",-1)),e[20]||(e[20]=t(". In this state, ",-1)),n(r,{type:"class",name:"Channel",method:"getMessageKeys"}),e[21]||(e[21]=t(" returns only the channel's ",-1)),e[22]||(e[22]=a("a",{href:"#deep-history"},"deep history",-1)),e[23]||(e[23]=t(" shard — the frozen archive of past messages. The channel becomes read-only until new budget is allocated. The name borrows from biology, where cryptobiosis is the suspended state some organisms enter under resource deprivation.",-1))]),e[79]||(e[79]=o('<p>Also called &quot;frozen,&quot; &quot;deep freeze,&quot; or &quot;deep history mode.&quot;</p><p>In os384: cryptobiosis is not an error condition — it is an inherent property of the storage model. A channel in cryptobiosis can always be read (history is never lost) and can always be revived by allocating new budget via <a href="#budd">budd</a> or a <a href="#storage-token">storage token</a>.</p><p><em>Related: <a href="#deep-history">deep history</a>, <a href="#storage-budget">Storage Budget</a>, <a href="#ttl">TTL</a>, <a href="#budd">budd</a></em></p><hr><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><h3 id="deduplication" tabindex="-1">deduplication <a class="header-anchor" href="#deduplication" aria-label="Permalink to &quot;deduplication&quot;">​</a></h3><p>The process by which the <a href="#storage-server">Storage Server</a> avoids storing the same data twice — even across different users and channels — without ever seeing the plaintext. The first half of the <a href="#fn">FN</a> (h1) is derived from the SHA-512 hash of the <em>unencrypted</em> content, so the server can recognize identical content without being able to read it. If an object with a given FN already exists, the server discards the new upload and returns the stored <a href="#verification">verification</a> token.</p><p>In os384: privacy-preserving deduplication is a deliberate design goal. Two users uploading the same file will silently share the stored shard. Neither party can detect this from the outside, and the server cannot read either copy.</p><p><em>Related: <a href="#fn">FN</a>, <a href="#verification">verification</a>, <a href="#shard">Shard</a>, <a href="#object">object</a>, <a href="#padding">padding</a>, <a href="#privacy-window">Privacy Window</a></em></p><hr><h3 id="deep-history" tabindex="-1">deep history <a class="header-anchor" href="#deep-history" aria-label="Permalink to &quot;deep history&quot;">​</a></h3><p>The permanent, shard-based archive of a channel&#39;s message log. Messages with infinite <a href="#ttl">TTL</a> (the default) are eventually moved from the active message map into deep history when the live message set exceeds the channel server&#39;s maximum. Deep history is stored as a structured tree of <a href="#shard">shards</a> (a Merkle-like history tree).</p><p>This is the mechanism by which the channel message log <em>becomes</em> shard storage: the channel server chunks the message history and stores it as encrypted blobs on the storage server. The resulting shards have no knowledge of their origin — they are opaque bytes like any other shard. Deep history is always available, even for channels in <a href="#cryptobiosis">cryptobiosis</a>.</p><p><em>Related: <a href="#cryptobiosis">cryptobiosis</a>, <a href="#ttl">TTL</a>, <a href="#shard">Shard</a>, <a href="#channel">Channel</a></em></p>',14)),a("p",null,[a("em",null,[e[24]||(e[24]=t("API: ",-1)),n(r,{type:"interface",name:"MessageHistory"}),e[25]||(e[25]=t(", ",-1)),n(r,{type:"interface",name:"DeepHistory"}),e[26]||(e[26]=t(", ",-1)),n(r,{type:"interface",name:"HistoryTree"})])]),e[80]||(e[80]=o('<hr><h3 id="dehydrated-key" tabindex="-1">dehydrated key <a class="header-anchor" href="#dehydrated-key" aria-label="Permalink to &quot;dehydrated key&quot;">​</a></h3><p>A compressed form of a <a href="#p-384-secp384r1">P-384</a> private key that stores only the scalar <code>d</code> (the private key material), without the public key coordinates <code>x</code> and <code>y</code>. Identified in the wire format by the <code>XjZx</code> key prefix (compared to <code>Xj34</code> for a full private key). The public key can be recomputed from <code>d</code> at any time, but this requires additional computation. Dehydrated keys are more compact for storage and transmission.</p><p>In os384: use <code>hydrateKey(privKey, pubKey?)</code> to reconstitute a dehydrated key into its full form. The <code>pubKey</code> argument can supply the <code>x</code> coordinate when you have the public key available separately.</p><p><em>Related: <a href="#p-384-secp384r1">P-384</a>, <a href="#owner-key">Owner Key</a>, <a href="#sb384">SB384</a>, <a href="#public-key-pair">Public Key Pair</a></em></p>',5)),a("p",null,[a("em",null,[e[27]||(e[27]=t("API: ",-1)),n(r,{type:"function",name:"hydrateKey"})])]),e[81]||(e[81]=o('<hr><h3 id="durable-object" tabindex="-1">Durable Object <a class="header-anchor" href="#durable-object" aria-label="Permalink to &quot;Durable Object&quot;">​</a></h3><p>Cloudflare&#39;s implementation of an <a href="#addressable-worker">addressable worker</a>. A Durable Object is a unique, persistent JavaScript worker instance with its own local storage (<a href="#kv_local">KV_local</a>) and WebSocket support, globally addressable by a unique identifier. In os384, each <a href="#channel">Channel</a> is backed by a Durable Object.</p><p>In os384: &quot;Durable Object&quot; and &quot;addressable worker&quot; are used interchangeably in the code and documentation. The os384 design is not tied to Cloudflare specifically — Durable Objects are the reference implementation of the addressable worker concept for the current deployment.</p><p><em>Related: <a href="#addressable-worker">addressable worker</a>, <a href="#kv_local">KV_local</a>, <a href="#channel">Channel</a></em></p><p><em>External: <a href="https://developers.cloudflare.com/durable-objects/" target="_blank" rel="noreferrer">Cloudflare Durable Objects docs</a></em></p><hr><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><h3 id="e2e-encryption-end-to-end-encryption" tabindex="-1">E2E Encryption (End-to-End Encryption) <a class="header-anchor" href="#e2e-encryption-end-to-end-encryption" aria-label="Permalink to &quot;E2E Encryption (End-to-End Encryption)&quot;">​</a></h3><p>Encryption where only the communicating parties can read messages — nothing in between (servers, networks, operators) has access. Conventional E2E means: secure <em>assuming</em> you trust all parts of the system. os384 distinguishes a stronger variant: &quot;true E2E,&quot; where even the key management infrastructure cannot access messages once a channel is <a href="#restricted">restricted</a> and the owner has rotated their keys. At that point, neither the channel server, the storage server, nor any cloud infrastructure provider can read content or establish participant identity.</p><p>In os384: all messages are encrypted. Unrestricted channels use server-assisted key distribution (the server facilitates key exchange but cannot read message content). Restricted channels with rotated keys give the server no useful access at all.</p><p><em>Related: <a href="#restricted">Restricted</a>, <a href="#channel">Channel</a>, <a href="#owner-key">Owner Key</a>, <a href="#protocol">protocol</a>, <a href="#micro-federation">Micro Federation</a>, <a href="#sovereignty">sovereignty</a></em></p><p><em>Read more: <a href="/BhoW6b/background.html">background</a></em></p><hr><h3 id="ecdh-elliptic-curve-diffie-hellman" tabindex="-1">ECDH (Elliptic Curve Diffie-Hellman) <a class="header-anchor" href="#ecdh-elliptic-curve-diffie-hellman" aria-label="Permalink to &quot;ECDH (Elliptic Curve Diffie-Hellman)&quot;">​</a></h3><p>A key agreement protocol: two parties can each derive an identical shared secret from their own private key and the other party&#39;s public key, without ever transmitting the secret. The result is a symmetric encryption key both parties can independently compute.</p><p>In os384: ECDH over <a href="#p-384">P-384</a> is the &quot;whisper&quot; protocol (<code>Protocol_ECDH</code>) used for private 1:1 messages between an owner and a specific visitor. Both parties derive the same AES key from their own private key and the other&#39;s public key.</p><p><em>Related: <a href="#p-384">P-384</a>, <a href="#aes-256-gcm">AES-256-GCM</a>, <a href="#protocol">protocol</a></em></p>',18)),a("p",null,[a("em",null,[e[28]||(e[28]=t("API: ",-1)),n(r,{type:"enumeration",name:"SBProtocol"})])]),e[82]||(e[82]=o('<hr><h3 id="edge-native" tabindex="-1">edge-native <a class="header-anchor" href="#edge-native" aria-label="Permalink to &quot;edge-native&quot;">​</a></h3><p>An architectural approach where computation is distributed to the &quot;edge&quot; of the network — inside browsers (client side) and lightweight cloud workers (server side) — rather than concentrated in central data centers. The key observation behind os384&#39;s design is that the combined computing power of browsers and edge workers now exceeds traditional centralized cloud infrastructure.</p><p>In os384: &quot;edge-native&quot; means all sensitive operations (key generation, encryption, decryption) happen on the client device. The servers are deliberately minimal and cannot read user data. Backend services (<a href="#channel-server">Channel Server</a>, <a href="#storage-server">Storage Server</a>) are implemented as edge workers that require no privileged access to operate.</p><p><em>Related: <a href="#addressable-worker">addressable worker</a>, <a href="#non-addressable-worker">non-addressable worker</a>, <a href="#loader">Loader</a>, <a href="#sovereignty">sovereignty</a></em></p><hr><h3 id="env-js" tabindex="-1">env.js <a class="header-anchor" href="#env-js" aria-label="Permalink to &quot;env.js&quot;">​</a></h3><p>A gitignored JavaScript file (<code>lib384/env.js</code>, <code>services/env.js</code>) that bridges environment-specific configuration into browser and Deno contexts. It exports <code>globalThis.env</code> with fields like <code>localBudgetKey</code>, <code>localLedgerKey</code>, <code>localWalletHandle</code>, and <code>configServerType</code>, which <code>config.js</code> reads to configure server URLs and key material.</p><p><code>env.js</code> is a transitional mechanism — browsers cannot read Unix environment variables, so this file acts as the bridge. Copy <code>env.example.js</code> as a template and fill in your local keys after <a href="#bootstrap">bootstrapping</a> a budget channel. Never commit a populated <code>env.js</code>; it contains private key material.</p><p>In Deno contexts the CLI reads environment variables directly (<code>OS384_BUDGET_KEY</code>, <code>OS384_LEDGER_KEY</code>, etc.) and does not use <code>env.js</code>.</p><p><em>Related: <a href="#budget-channel">budget channel</a>, <a href="#cli">CLI</a>, <a href="#bootstrap">bootstrap</a></em></p><p><em>Read more: <a href="/BhoW6b/dev/local-stack.html">dev/local-stack</a></em></p><hr><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><h3 id="file" tabindex="-1">file <a class="header-anchor" href="#file" aria-label="Permalink to &quot;file&quot;">​</a></h3><p>In os384, &quot;file&quot; is used broadly: any stored item — image, video, document, arbitrary binary data. os384 has no directory hierarchy; files are modeled as sets with path properties rather than as entries in a physical folder structure. The underlying storage primitive is an <a href="#sbfs">SBFile</a>, which wraps one or more <a href="#object">ObjectHandles</a> (shards).</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#object">object</a>, <a href="#sbfs">SBFS</a></em></p>',17)),a("p",null,[a("em",null,[e[29]||(e[29]=t("API: ",-1)),n(r,{type:"class",name:"SBFile"})])]),e[83]||(e[83]=o('<hr><h3 id="fileset" tabindex="-1">FileSet <a class="header-anchor" href="#fileset" aria-label="Permalink to &quot;FileSet&quot;">​</a></h3><p>A packaged collection of static files (HTML, JS, CSS, assets) bundled together as a single <a href="#shard">shard</a>. FileSets are the delivery format for os384 apps: the <a href="#loader">Loader</a> fetches a FileSet shard, reconstructs a virtual file system (<a href="#sbfs">SBFS</a>) from it, and serves the app to the browser via a <a href="#service-worker">Service Worker</a>. Conceptually equivalent to a ZIP of a static web site, but encrypted, content-addressed, and served without the server knowing what it contains.</p><p><em>Related: <a href="#loader">Loader</a>, <a href="#sbfs">SBFS</a>, <a href="#service-worker">Service Worker</a>, <a href="#shard">Shard</a></em></p><hr><h3 id="fn-full-name" tabindex="-1">FN (Full Name) <a class="header-anchor" href="#fn-full-name" aria-label="Permalink to &quot;FN (Full Name)&quot;">​</a></h3><p>The globally unique identifier of a stored <a href="#object">object</a>. An FN is derived by taking the SHA-512 hash of the padded, unencrypted content and splitting it into two 256-bit halves: <strong>h1</strong> (the first half, used as the server-side lookup key) and <strong>h2</strong> (the second half, used as the client-side encryption key material). The server never sees h2.</p><p>The two-half construction enables private <a href="#deduplication">deduplication</a>: h1 is sent to the storage server to retrieve a <a href="#nonce">nonce</a> and <a href="#salt">salt</a> — the server recognizes the same h1 for identical content and returns the same values. The client then uses h2 + salt with <a href="#pbkdf2-password-based-key-derivation-function-2">PBKDF2</a> (100,000 iterations) to derive the encryption key independently. The final storage address of the shard is a <em>separate</em> SHA-256 hash taken over (iv + salt + encrypted data) — a third hash distinct from h1 and h2.</p><p>The <a href="#objecthandle">ObjectHandle</a> returned from a successful store operation contains the shard&#39;s storage ID, the decryption key (h2 in base62), and the verification token — everything needed to retrieve and decrypt the shard later.</p><p><em>Related: <a href="#object">object</a>, <a href="#shard">Shard</a>, <a href="#verification">verification</a>, <a href="#deduplication">deduplication</a>, <a href="#objecthandle">ObjectHandle</a></em></p>',10)),a("p",null,[a("em",null,[e[30]||(e[30]=t("API: ",-1)),n(r,{type:"function",name:"sbCrypto.generateIdKey"})])]),e[84]||(e[84]=o('<hr><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><h3 id="iv-initialization-vector" tabindex="-1">iv (Initialization Vector) <a class="header-anchor" href="#iv-initialization-vector" aria-label="Permalink to &quot;iv (Initialization Vector)&quot;">​</a></h3><p>A random value used in encryption to ensure that encrypting the same data twice with the same key produces different ciphertexts. Without an IV, an attacker could detect when the same message is sent repeatedly. The IV does not need to be kept secret — it is stored alongside the encrypted data.</p><p>In os384: IVs are used in <a href="#aes-256-gcm">AES-256-GCM</a> encryption of <a href="#shard">shards</a> and messages. In authenticated encryption contexts, the terms &quot;iv&quot; and &quot;<a href="#nonce">nonce</a>&quot; are used interchangeably.</p><p><em>Related: <a href="#nonce">nonce</a>, <a href="#salt">salt</a>, <a href="#aes-256-gcm">AES-256-GCM</a></em></p><hr><h2 id="k" tabindex="-1">K <a class="header-anchor" href="#k" aria-label="Permalink to &quot;K&quot;">​</a></h2><h3 id="key" tabindex="-1">key <a class="header-anchor" href="#key" aria-label="Permalink to &quot;key&quot;">​</a></h3><p>os384 identities are <a href="#p-384-secp384r1">P-384</a> elliptic-curve key pairs. The system uses <a href="#base62">base62</a>-encoded representations with type-discriminating prefixes so that any key string is self-describing. All prefixes are defined in lib384&#39;s <code>SBCrypto</code> module (<code>KeyPrefix</code> and <code>KeySubPrefix</code> enums).</p><p><strong>Prefix scheme:</strong></p><p>Every encoded key begins with a 3- or 4-character prefix. The first three characters identify the key type, and a fourth character (the &quot;sub-prefix&quot;) encodes either the parity of the y-coordinate or whether the key is dehydrated:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>PNk2</code></td><td>Public key</td><td>Compressed, y-coordinate is even</td></tr><tr><td><code>PNk3</code></td><td>Public key</td><td>Compressed, y-coordinate is odd</td></tr><tr><td><code>Xj32</code></td><td>Private key</td><td>Compressed (includes public), y even</td></tr><tr><td><code>Xj33</code></td><td>Private key</td><td>Compressed (includes public), y odd</td></tr><tr><td><code>Xj34</code></td><td>Private key</td><td>Uncompressed (full x + y + d)</td></tr><tr><td><code>XjZx</code></td><td>Dehydrated private key</td><td>Private scalar only (public components omitted; can be recomputed)</td></tr></tbody></table><p>The <code>2</code>/<code>3</code> sub-prefix comes from the SEC 1 compressed-point convention: <code>0x02</code> for even y, <code>0x03</code> for odd y. Parity is determined by the least-significant bit of the last byte of the y-coordinate.</p><p><strong>Key representations:</strong></p><p>A single <a href="#sb384">SB384</a> identity can be viewed through several &quot;perspectives&quot;:</p><ul><li><strong>Private key</strong> (<code>Xj32</code>/<code>Xj33</code>): The full key pair — everything needed to act as this identity. This is what you store and pass to <code>-k</code> flags.</li><li><strong>Public key</strong> (<code>PNk2</code>/<code>PNk3</code>): The public half only. Safe to share; used by others to encrypt to you or verify your signatures.</li><li><strong>Dehydrated key</strong> (<code>XjZx</code>): A shorter form of the private key that omits the public components (since they can be recomputed from the private scalar and the curve). Useful when you&#39;re already storing the public key separately.</li><li><strong>Channel ID / User ID</strong>: A hash of the public key. This is how the rest of the system refers to an identity — it&#39;s the address, not the key itself.</li></ul><p>Use <code>384 key</code> to generate a new identity or <code>384 key -k &lt;privateKey&gt;</code> to inspect an existing one and see all representations.</p><p><em>Related: <a href="#sb384">SB384</a>, <a href="#p-384-secp384r1">P-384</a>, <a href="#base62">base62</a>, <a href="#channel-id">channel ID</a></em></p><p><em>Read more: <a href="/BhoW6b/cli.html#key">CLI Reference — key command</a></em></p><hr><h3 id="kv-global" tabindex="-1">KV_global <a class="header-anchor" href="#kv-global" aria-label="Permalink to &quot;KV_global&quot;">​</a></h3><p>A key-value store accessible by all workers — both <a href="#channel-server">Channel Server</a> and <a href="#storage-server">Storage Server</a> instances. Used for data that must be readable from any worker: stored <a href="#shard">objects (shards)</a>, <a href="#storage-token">storage tokens</a>, and other global state. Designed to tolerate eventual consistency — reads may be slightly stale. In the Cloudflare implementation, this is Cloudflare Workers KV.</p><p><em>Related: <a href="#kv_local">KV_local</a>, <a href="#shard">Shard</a>, <a href="#non-addressable-worker">non-addressable worker</a></em></p><p><em>Read more: <a href="/BhoW6b/storage.html">storage</a></em></p><hr><h3 id="kv-local" tabindex="-1">KV_local <a class="header-anchor" href="#kv-local" aria-label="Permalink to &quot;KV_local&quot;">​</a></h3><p>A key-value store private to a specific <a href="#addressable-worker">addressable worker</a> instance, and hence to a specific <a href="#channel">Channel</a>. Used for data requiring strong consistency: active message state, visitor keys, channel metadata, and administrative data. In the Cloudflare implementation, this is Durable Object storage.</p><p>Not to be confused with browser <a href="#local-storage">Local Storage</a> on the client.</p><p><em>Related: <a href="#kv_global">KV_global</a>, <a href="#addressable-worker">addressable worker</a>, <a href="#durable-object">Durable Object</a></em></p><p><em>Read more: <a href="/BhoW6b/storage.html">storage</a></em></p><hr><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><h3 id="ledger-channel" tabindex="-1">ledger channel <a class="header-anchor" href="#ledger-channel" aria-label="Permalink to &quot;ledger channel&quot;">​</a></h3><p>An informal term for a <a href="#channel">Channel</a> used to record metadata and operational history — such as which channels were created, when, and for what purpose. Not a distinct type in the os384 protocol; just a common usage pattern. The ledger is kept separate from the <a href="#budget-channel">budget channel</a> so that bookkeeping never gets starved of <a href="#storage-budget">storage budget</a> — even if the budget channel is nearly exhausted, the ledger retains its own small reserve and can still accept new records.</p><p>A typical setup (e.g. via <code>384 init</code>) creates a ledger channel first from a <a href="#storage-token">storage token</a>, then mints most of that budget off to a separate budget channel. The ledger keeps a small reserve and serves as the authoritative log of what was done.</p><p><em>Related: <a href="#budget-channel">budget channel</a>, <a href="#budd">budd</a>, <a href="#storage-budget">Storage Budget</a>, <a href="#channel">Channel</a>, <a href="#cli">CLI</a></em></p><hr><h3 id="loader" tabindex="-1">Loader <a class="header-anchor" href="#loader" aria-label="Permalink to &quot;Loader&quot;">​</a></h3><p>The os384 component that runs in the browser as the system&#39;s entry point — functioning simultaneously as microkernel, virtual machine manager, and bootloader. When you navigate to a 384.dev URL, the Loader interprets the URL fragment (which carries an app identifier or shard reference without transmitting it to any server), fetches the appropriate <a href="#fileset">FileSet</a> from a channel server, sets up a virtual file system (<a href="#sbfs">SBFS</a>) in a fresh browser subdomain, and launches the app via a <a href="#service-worker">Service Worker</a>. The Loader itself never persists user data; all key management happens in the app context it spawns.</p><p>In os384: the Loader is intentionally minimal and auditable. It can also be run locally from a static HTML file, completely independent of 384.dev infrastructure.</p><p><em>Related: <a href="#fileset">FileSet</a>, <a href="#sbfs">SBFS</a>, <a href="#service-worker">Service Worker</a>, <a href="#wallet">Wallet</a>, <a href="#channel">Channel</a></em></p><p><em>Read more: <a href="/BhoW6b/loader.html">loader</a></em></p><hr><h3 id="local-storage" tabindex="-1">Local Storage <a class="header-anchor" href="#local-storage" aria-label="Permalink to &quot;Local Storage&quot;">​</a></h3><p>In the browser, <code>window.localStorage</code> — a persistent key-value store scoped to a specific origin. In os384, Local Storage is where channel keys, visitor information, and <a href="#wallet">Wallet</a> state are kept on the client device. It is never synced or held by any server.</p><p>In os384: if Local Storage is cleared, the user must restore from a backup (exported key file or wallet recovery). This is a deliberate privacy trade-off — the server never holds these keys and therefore cannot assist in recovery.</p><p><em>Related: <a href="#wallet">Wallet</a>, <a href="#vault">Vault</a>, <a href="#sovereignty">sovereignty</a></em></p><p><em>Read more: <a href="/BhoW6b/local-storage.html">local-storage</a></em></p><hr><h3 id="locked" tabindex="-1">locked <a class="header-anchor" href="#locked" aria-label="Permalink to &quot;locked&quot;">​</a></h3><p>A <a href="#channel">Channel</a> state in which only pre-approved <a href="#visitor">Visitors</a> can join. Activated by the owner calling <code>channel.lock()</code>. After locking, new visitors must be individually accepted via <code>channel.acceptVisitor(userId)</code> before they can connect. The locked state is stored as a flag in the channel&#39;s server-side data and is reported in <code>ChannelAdminData.locked</code>.</p><p>In os384: locking is the channel owner&#39;s primary access-control mechanism for private channels. An unlocked channel permits any user to join (subject to <a href="#capacity">capacity</a>). A locked channel is sometimes described as &quot;restricted&quot; or &quot;closed&quot; in informal usage.</p><p><em>Related: <a href="#restricted">Restricted</a>, <a href="#capacity">capacity</a>, <a href="#visitor">Visitor</a>, <a href="#owner">Owner</a></em></p>',54)),a("p",null,[a("em",null,[e[31]||(e[31]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"lock"})])]),e[85]||(e[85]=o('<hr><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><h3 id="manifest" tabindex="-1">manifest <a class="header-anchor" href="#manifest" aria-label="Permalink to &quot;manifest&quot;">​</a></h3><p>Two related uses in os384:</p><ol><li><p>The set of cryptographic information needed to fetch and decrypt a stored <a href="#object">object</a>: <a href="#fn">FN</a>, <a href="#verification">verification</a>, <a href="#salt">salt</a>, <a href="#iv">iv</a>, and size. Together these are the &quot;key&quot; to an encrypted shard — without the manifest you cannot retrieve or decrypt the object. Manifests typically travel as <a href="#channel">Channel</a> messages, since <a href="#shard">shards</a> themselves carry no metadata.</p></li><li><p>The application manifest (<code>384.manifest.json</code>) used by <a href="#appmain">AppMain</a> to declare an app&#39;s entry point, dependencies, and resource channels. During local development a dotfile variant (<code>.384.manifest.json</code>) acts as a <a href="#shadow-manifest">shadow manifest</a> that takes priority over the published one.</p></li></ol><p><em>Related: <a href="#fn">FN</a>, <a href="#verification">verification</a>, <a href="#object">object</a>, <a href="#appmain">AppMain</a>, <a href="#channel">Channel</a>, <a href="#shadow-manifest">shadow manifest</a></em></p><hr><h3 id="message" tabindex="-1">Message <a class="header-anchor" href="#message" aria-label="Permalink to &quot;Message&quot;">​</a></h3><p>The unit of communication on a <a href="#channel">Channel</a>. Every message has a body (arbitrary content), a sender (identified by <code>SBUserId</code>), a server-assigned timestamp, a <a href="#ttl">TTL</a>, and a unique <code>_id</code> (format: <code>channelId__subChannel__timestampPrefix</code>). Messages are encrypted end-to-end; the server routes them but cannot read the body.</p><p>Messages with default <a href="#ttl">TTL</a> (15, permanent) are stored forever — first in the channel&#39;s active message map, then archived into <a href="#deep-history">deep history</a>. <code>TTL=0</code> messages are ephemeral and never stored.</p><p>Because <a href="#shard">shards</a> carry zero metadata, channel messages are also the mechanism for distributing shard manifests — the information needed to retrieve and decrypt a stored object is always communicated as a message.</p><p><em>Related: <a href="#ttl">TTL</a>, <a href="#channel">Channel</a>, <a href="#deep-history">deep history</a>, <a href="#subchannel">SubChannel</a>, <a href="#manifest">manifest</a></em></p>',12)),a("p",null,[a("em",null,[e[32]||(e[32]=t("API: ",-1)),n(r,{type:"interface",name:"Message"}),e[33]||(e[33]=t(", ",-1)),n(r,{type:"class",name:"Channel",method:"send"})])]),e[86]||(e[86]=o('<hr><h3 id="micro-federation" tabindex="-1">Micro Federation <a class="header-anchor" href="#micro-federation" aria-label="Permalink to &quot;Micro Federation&quot;">​</a></h3><p>The ability for an established, <a href="#restricted">restricted</a> channel and its participants to &quot;leave&quot; their origin server and reconstitute on any other server without losing continuity. Also called <em>severability</em>.</p><p>Once a channel is restricted and the <a href="#owner">Owner</a> has rotated their keys, every participant holds the public keys of every other participant in their local storage. Moving servers requires only that someone hosts a new one and securely shares its address — each participant exports their key file, connects to the new server, imports their keys, and the channel resumes. The storage components (<a href="#shard">shards</a>) are independent: objects are content-addressed and can remain on the original storage server or be migrated separately as desired.</p><p>In os384: Micro Federation is a core <a href="#sovereignty">sovereignty</a> property. No server operator — including 384, Inc. — can permanently cut off a group from their own conversation.</p><p><em>Related: <a href="#restricted">Restricted</a>, <a href="#owner-key">Owner Key</a>, <a href="#sovereignty">sovereignty</a>, <a href="#channel">Channel</a>, <a href="#local-storage">Local Storage</a></em></p><hr><h3 id="mirror" tabindex="-1">mirror <a class="header-anchor" href="#mirror" aria-label="Permalink to &quot;mirror&quot;">​</a></h3><p>A read-only replica of a <a href="#storage-server">Storage Server</a>. A mirror stores <a href="#shard">shards</a> indexed by their content address and serves them via the standard fetch API, but cannot accept new uploads. Because shard IDs are <a href="#content-addressing">content-addressed</a> and globally unique, any mirror can serve any shard without coordination — a client with the shard ID and <a href="#verification">verification</a> token can retrieve the shard from any mirror that has it.</p><p>In os384: mirrors are useful for performance (CDN-like caching), redundancy, and offline access. Running a local mirror during development (<code>mirror.py</code>) caches shards on your machine to avoid repeated fetches from the network.</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#storage-server">Storage Server</a>, <a href="#content-addressing">content addressing</a>, <a href="#verification">verification</a></em></p><hr><h3 id="motd-message-of-the-day" tabindex="-1">MOTD (Message of the Day) <a class="header-anchor" href="#motd-message-of-the-day" aria-label="Permalink to &quot;MOTD (Message of the Day)&quot;">​</a></h3><p>An optional message set by the <a href="#owner">Owner</a> of a <a href="#channel">Channel</a>, displayed to any participant joining or re-joining the channel. Can be changed by the owner at any time.</p><p><em>Related: <a href="#owner">Owner</a>, <a href="#channel">Channel</a>, <a href="#page">Page</a></em></p><hr><h3 id="mother-channel" tabindex="-1">mother channel <a class="header-anchor" href="#mother-channel" aria-label="Permalink to &quot;mother channel&quot;">​</a></h3><p>The <a href="#channel">Channel</a> from which a given channel was <a href="#budd">budded</a>. When <code>channel.budd()</code> creates a new channel, the new channel records the origin as its mother channel (retrievable via <code>channel.getMother()</code>). This creates a lineage tree that tracks how storage budget was allocated and can be used for auditing.</p><p>In os384: the mother channel relationship is stored server-side. A channel cannot be re-parented; the mother channel is set at creation and does not change.</p><p><em>Related: <a href="#budd">budd</a>, <a href="#storage-budget">Storage Budget</a>, <a href="#budget-channel">budget channel</a></em></p>',20)),a("p",null,[a("em",null,[e[34]||(e[34]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"getMother"})])]),e[87]||(e[87]=o('<hr><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><h3 id="non-addressable-worker" tabindex="-1">non-addressable worker <a class="header-anchor" href="#non-addressable-worker" aria-label="Permalink to &quot;non-addressable worker&quot;">​</a></h3><p>An edge computing worker with no persistent global identity. When a client connects to a non-addressable worker, the infrastructure routes it to any available instance — there is no control over which one. Non-addressable workers have no local storage; all state must come from <a href="#kv_global">KV_global</a>. They scale horizontally without limit, making them ideal for stateless operations (fetching <a href="#shard">shards</a>, API calls that don&#39;t require channel-specific state). Contrast with <a href="#addressable-worker">addressable worker</a>.</p><p>In os384: shard fetch and store operations go through non-addressable workers; channel-specific operations (sending messages, managing visitors) require an <a href="#addressable-worker">addressable worker</a>.</p><p><em>Related: <a href="#addressable-worker">addressable worker</a>, <a href="#durable-object">Durable Object</a>, <a href="#kv_global">KV_global</a></em></p><hr><h3 id="nonce" tabindex="-1">nonce <a class="header-anchor" href="#nonce" aria-label="Permalink to &quot;nonce&quot;">​</a></h3><p>A &quot;number used once&quot; — a random value included in encryption to prevent an attacker from detecting when the same message is sent repeatedly. In <a href="#aes-256-gcm">AES-256-GCM</a>, the nonce ensures that encrypting the same plaintext with the same key produces different ciphertext every time.</p><p>In os384: nonces are used in all shard and message encryption. In authenticated encryption contexts, &quot;nonce&quot; and &quot;<a href="#iv">iv</a>&quot; are used interchangeably.</p><p><em>Related: <a href="#iv">iv</a>, <a href="#salt">salt</a>, <a href="#aes-256-gcm">AES-256-GCM</a></em></p><hr><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><h3 id="object" tabindex="-1">object <a class="header-anchor" href="#object" aria-label="Permalink to &quot;object&quot;">​</a></h3><p>An immutable, encrypted, content-addressed blob of data stored in os384. Every object has a globally unique <a href="#fn">FN</a> derived from its contents, is encrypted before leaving the client, is <a href="#padding">padded</a> to obscure its true size, and is stored with a server-assigned <a href="#verification">verification</a> token. Objects have no metadata of any kind — no name, no type, no owner. All such context must be communicated separately through <a href="#channel">Channel</a> messages. An <a href="#object">ObjectHandle</a> contains all the information needed to retrieve and decrypt an object.</p><p>&quot;Object&quot; and &quot;<a href="#shard">Shard</a>&quot; refer to the same storage unit — &quot;object&quot; emphasizes the logical view, &quot;shard&quot; the physical storage unit.</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#fn">FN</a>, <a href="#verification">verification</a>, <a href="#deduplication">deduplication</a>, <a href="#padding">padding</a>, <a href="#channel">Channel</a></em></p>',17)),a("p",null,[a("em",null,[e[35]||(e[35]=t("API: ",-1)),n(r,{type:"interface",name:"ObjectHandle"}),e[36]||(e[36]=t(", ",-1)),n(r,{type:"interface",name:"ShardInfo"})])]),e[88]||(e[88]=o('<hr><h3 id="objecthandle" tabindex="-1">ObjectHandle <a class="header-anchor" href="#objecthandle" aria-label="Permalink to &quot;ObjectHandle&quot;">​</a></h3><p>The complete in-memory descriptor for a <a href="#shard">Shard</a> — sufficient to retrieve, authenticate, and decrypt it. An ObjectHandle is what you hold after storing data and what you share with others to give them access to it.</p><p>Key fields: <code>id</code> (the content address, 43-char base62), <code>key</code> (the decryption key material, base62-encoded h2 half of SHA-512), <code>iv</code> and <code>salt</code> (returned by the server, needed for decryption), <code>verification</code> (the server-issued access token), and optionally <code>payload</code> (the decrypted contents, populated after <code>fetchData()</code>). Also carries <code>storageServer</code> (a hint for where to fetch it) and <code>type</code> (MIME type).</p><p>To <strong>retrieve</strong> a shard you need <code>id</code> + <code>verification</code>. To <strong>decrypt</strong> it you additionally need <code>key</code> + <code>iv</code> + <code>salt</code>. The storage server supplies <code>iv</code> and <code>salt</code> on fetch if you provide <code>id</code> + <code>verification</code>.</p><p>Distinct from <a href="#shard">ShardInfo</a> (the server&#39;s minimal representation, which only has <code>id</code>, <code>iv</code>, <code>salt</code>).</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#fn-full-name">FN</a>, <a href="#verification">verification</a>, <a href="#object">object</a></em></p>',7)),a("p",null,[a("em",null,[e[37]||(e[37]=t("API: ",-1)),n(r,{type:"interface",name:"ObjectHandle"}),e[38]||(e[38]=t(", ",-1)),n(r,{type:"class",name:"StorageApi",method:"storeData"}),e[39]||(e[39]=t(", ",-1)),n(r,{type:"class",name:"StorageApi",method:"fetchData"})])]),e[89]||(e[89]=o('<hr><h3 id="origin-server" tabindex="-1">Origin Server <a class="header-anchor" href="#origin-server" aria-label="Permalink to &quot;Origin Server&quot;">​</a></h3><p>The <a href="#channel-server">Channel Server</a> at whose domain a particular <a href="#channel-id">Channel ID</a> was first allocated. The origin server is not tracked or recorded in any central registry — there is no authority over channel assignment. Once a channel exists, it can migrate to other servers via <a href="#micro-federation">Micro Federation</a>. The concept of an origin server is relevant mainly for auditing.</p><p><em>Related: <a href="#channel">Channel</a>, <a href="#channel-server">Channel Server</a>, <a href="#micro-federation">Micro Federation</a></em></p><hr><h3 id="owner" tabindex="-1">Owner <a class="header-anchor" href="#owner" aria-label="Permalink to &quot;Owner&quot;">​</a></h3><p>The entity that holds the private key corresponding to a <a href="#channel">Channel&#39;s</a> <a href="#channel-id">Channel ID</a>. The owner has exclusive rights to all administrative operations: accepting <a href="#visitor">visitors</a>, <a href="#restricted">restricting</a> the channel, setting the <a href="#motd">MOTD</a>, rotating keys, <a href="#budd">budding</a> channels, setting capacity, and setting <a href="#page">Pages</a>. There is exactly one owner per channel, determined solely by possession of the private key — not by any server-side record.</p><p><em>Related: <a href="#owner-key">Owner Key</a>, <a href="#channel">Channel</a>, <a href="#restricted">Restricted</a>, <a href="#channel-handle">channel handle</a></em></p>',8)),a("p",null,[a("em",null,[e[40]||(e[40]=t("API: ",-1)),n(r,{type:"class",name:"ChannelKeys",method:"owner"})])]),e[90]||(e[90]=o('<hr><h3 id="owner-key" tabindex="-1">Owner Key <a class="header-anchor" href="#owner-key" aria-label="Permalink to &quot;Owner Key&quot;">​</a></h3><p>The <a href="#p-384">P-384</a> private key from which a channel&#39;s <a href="#channel-id">Channel ID</a> is derived. It is the root of a channel&#39;s identity: without it, no administrative operation on the channel is possible. The Channel ID is the SHA-384 hash of the corresponding public key. Owner keys are unique per channel — the same user has different owner keys for different channels, providing privacy isolation between channels.</p><p><em>Related: <a href="#owner">Owner</a>, <a href="#channel-id">Channel ID</a>, <a href="#p-384">P-384</a></em></p>',4)),a("p",null,[a("em",null,[e[41]||(e[41]=t("API: ",-1)),n(r,{type:"class",name:"SB384",method:"userPrivateKey"}),e[42]||(e[42]=t(", ",-1)),n(r,{type:"class",name:"SB384",method:"ownerChannelId"})])]),e[91]||(e[91]=o('<hr><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><h3 id="page-channel-page" tabindex="-1">page (Channel Page) <a class="header-anchor" href="#page-channel-page" aria-label="Permalink to &quot;page (Channel Page)&quot;">​</a></h3><p>A single public-facing content object served by the <a href="#channel-server">Channel Server</a> at a fixed, unauthenticated URL path (<code>/api/v2/page/&lt;prefix&gt;</code>). Any MIME type is supported — JavaScript, HTML, PDF, JSON, images. Clients can read a page without any authentication; the channel owner sets the page content via <code>channel.setPage()</code>.</p><p>In os384: pages are the mechanism for hosting public static assets on top of channels. The Loader itself is served as a page, lib384 is served as a page, and apps typically expose their entry point via a page. A short &quot;page prefix&quot; can function like a URL shortener — the <code>#A1cQwk</code>-style fragment in os384 links resolves to a page prefix.</p><p><em>Related: <a href="#channel">Channel</a>, <a href="#loader">Loader</a>, <a href="#manifest">manifest</a>, <a href="#sbfs-os384-virtual-file-system">SBFS</a></em></p>',6)),a("p",null,[a("em",null,[e[43]||(e[43]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"setPage"}),e[44]||(e[44]=t(", ",-1)),n(r,{type:"class",name:"ChannelApi",method:"getPage"})])]),e[92]||(e[92]=o('<hr><h3 id="passphrase" tabindex="-1">passphrase <a class="header-anchor" href="#passphrase" aria-label="Permalink to &quot;passphrase&quot;">​</a></h3><p>The word-based component of a <a href="#wallet">Wallet</a> credential, complementing the <a href="#strongpin">strongpin</a>. A passphrase is a sequence of randomly selected plain-English words — the recommended baseline is three words, contributing approximately 39–42 bits of entropy. The passphrase is intended to be memorable or writable in natural language, while the strongpin is optimized for unambiguous transcription.</p><p>Together, strongpin + passphrase are the two inputs to <a href="#pbkdf2-password-based-key-derivation-function-2">PBKDF2</a> (10 million iterations) that derives the wallet&#39;s <a href="#p-384-secp384r1">P-384</a> private key. Neither alone is sufficient.</p><p>In os384: generated by <code>generatePassPhrase()</code>. Unlike the strongpin, the passphrase does not have a parity check — each word contributes independently.</p><p><em>Related: <a href="#strongpin">strongpin</a>, <a href="#wallet">Wallet</a>, <a href="#pbkdf2-password-based-key-derivation-function-2">PBKDF2</a></em></p>',6)),a("p",null,[a("em",null,[e[45]||(e[45]=t("API: ",-1)),n(r,{type:"function",name:"generatePassPhrase"})])]),e[93]||(e[93]=o('<hr><h3 id="p-384-secp384r1" tabindex="-1">P-384 (secp384r1) <a class="header-anchor" href="#p-384-secp384r1" aria-label="Permalink to &quot;P-384 (secp384r1)&quot;">​</a></h3><p>An elliptic curve defined by NIST standards, used for all public-key cryptography in os384. P-384 provides approximately 192 bits of security — meaningfully stronger than the more common P-256 (128-bit security). Key pairs on P-384 are used for <a href="#ecdh">ECDH</a> key agreement and digital signatures.</p><p>In os384: every user identity, channel identity, and ownership proof is ultimately grounded in a P-384 key pair. The &quot;384&quot; in os384 refers to this curve.</p><p><em>Related: <a href="#ecdh">ECDH</a>, <a href="#owner-key">Owner Key</a>, <a href="#public-key-pair">Public Key Pair</a></em></p>',5)),a("p",null,[a("em",null,[e[46]||(e[46]=t("API: ",-1)),n(r,{type:"class",name:"SB384"})])]),e[94]||(e[94]=o('<hr><h3 id="padding" tabindex="-1">padding <a class="header-anchor" href="#padding" aria-label="Permalink to &quot;padding&quot;">​</a></h3><p>The process of expanding an <a href="#object">object&#39;s</a> size to the nearest power of two before encryption, preventing the storage server from inferring content type or true size from the ciphertext length. The minimum padded size is 32 KiB; maximum is 32 MiB.</p><p>In os384: padding is a privacy measure. Without it, an object&#39;s size would leak information (e.g., a ~50 KB file is probably a compressed image). After padding, all objects in the same size bucket are indistinguishable to the storage server.</p><p><em>Related: <a href="#object">object</a>, <a href="#shard">Shard</a>, <a href="#aes-256-gcm">AES-256-GCM</a>, <a href="#deduplication">deduplication</a></em></p><hr><h3 id="payload-format" tabindex="-1">payload format <a class="header-anchor" href="#payload-format" aria-label="Permalink to &quot;payload format&quot;">​</a></h3><p>The binary serialization container used for all stored data and channel message bodies in os384. A payload is an <code>ArrayBuffer</code> prefixed with a 4-byte magic header (<code>0xAABBBBAA</code>), followed by a compact representation of any JavaScript value — objects, arrays, <code>ArrayBuffer</code>, <code>Map</code>, typed arrays, and more.</p><p>All content stored in os384 goes through <code>assemblePayload()</code> before encryption, and through <code>extractPayload()</code> after decryption. The payload format is what the encryption layer sees — the storage server only ever handles encrypted payloads and never knows their internal structure.</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#message">Message</a>, <a href="#object">object</a></em></p>',10)),a("p",null,[a("em",null,[e[47]||(e[47]=t("API: ",-1)),n(r,{type:"function",name:"assemblePayload"}),e[48]||(e[48]=t(", ",-1)),n(r,{type:"function",name:"extractPayload"})])]),e[95]||(e[95]=o('<hr><h3 id="pbkdf2-password-based-key-derivation-function-2" tabindex="-1">PBKDF2 (Password-Based Key Derivation Function 2) <a class="header-anchor" href="#pbkdf2-password-based-key-derivation-function-2" aria-label="Permalink to &quot;PBKDF2 (Password-Based Key Derivation Function 2)&quot;">​</a></h3><p>A standard algorithm for deriving a cryptographic key from a passphrase or other lower-entropy input. It applies a hash function many times in sequence (controlled by an iteration count), making brute-force guessing computationally expensive — each guess requires doing all the iterations.</p><p>In os384: PBKDF2 is used in two distinct contexts with different iteration counts. For shard encryption: 100,000 iterations, using the h2 half of the content&#39;s SHA-512 hash as key material — fewer iterations are appropriate since h2 is already high-entropy hash data, not a human password. For <a href="#wallet">Wallet</a> key derivation from a <a href="#strongpin">strongpin</a> + <a href="#passphrase">passphrase</a>: 10 million iterations — high because the input is human-chosen and must resist brute force. The wallet iteration count was upgraded from 100,000 in earlier versions.</p><p><em>Related: <a href="#wallet">Wallet</a>, <a href="#strongpin">strongpin</a>, <a href="#salt">salt</a>, <a href="#aes-256-gcm">AES-256-GCM</a>, <a href="#fn">FN</a></em></p>',5)),a("p",null,[a("em",null,[e[49]||(e[49]=t("API: ",-1)),n(r,{type:"class",name:"SBCrypto"})])]),e[96]||(e[96]=o('<hr><h3 id="perma" tabindex="-1">perma <a class="header-anchor" href="#perma" aria-label="Permalink to &quot;perma&quot;">​</a></h3><p>The unit of storage accounting in os384. One perma corresponds to permanently storing 4 KiB of data. Storage budgets, costs, and token values are expressed in permas.</p><p><em>Related: <a href="#storage-budget">Storage Budget</a>, <a href="#storage-token">storage token</a>, <a href="#shard">Shard</a></em></p><hr><h3 id="personal-channel-server" tabindex="-1">Personal Channel Server <a class="header-anchor" href="#personal-channel-server" aria-label="Permalink to &quot;Personal Channel Server&quot;">​</a></h3><p>An instance of a <a href="#channel-server">Channel Server</a> run for personal or private use, typically on hardware you control. Running your own channel server is the path to full <a href="#sovereignty">sovereignty</a> — your channels are not dependent on 384.dev or any third-party infrastructure. The server software and configuration are fully open source.</p><p><em>Related: <a href="#channel-server">Channel Server</a>, <a href="#sovereignty">sovereignty</a>, <a href="#micro-federation">Micro Federation</a></em></p><p><em>Read more: <a href="/BhoW6b/dev/local-stack.html">dev/local-stack</a></em></p><hr><h3 id="pii-personally-identifiable-information" tabindex="-1">PII (Personally Identifiable Information) <a class="header-anchor" href="#pii-personally-identifiable-information" aria-label="Permalink to &quot;PII (Personally Identifiable Information)&quot;">​</a></h3><p>Any data that can uniquely identify a specific individual — name, email address, phone number, device fingerprint, etc. os384 is designed to minimize PII in the system and to avoid exposing it to operators. In a fully <a href="#restricted">restricted</a> channel with rotated keys, even the channel operator holds no PII about participants.</p><p><em>Related: <a href="#sovereignty">sovereignty</a>, <a href="#e2e-encryption-end-to-end-encryption">E2E Encryption</a>, <a href="#restricted">Restricted</a></em></p><hr><h3 id="privacy-window" tabindex="-1">Privacy Window <a class="header-anchor" href="#privacy-window" aria-label="Permalink to &quot;Privacy Window&quot;">​</a></h3><p>A rolling 14-day period after which the per-object h1 prefix records used for <a href="#deduplication">deduplication</a> are discarded. The Privacy Window limits how long the server can correlate which objects were stored by the same channel. After the window expires, the h1 record is deleted — the stored <a href="#shard">shard</a> itself remains, but the deduplication index entry does not.</p><p><em>Related: <a href="#fn">FN</a>, <a href="#deduplication">deduplication</a>, <a href="#object">object</a></em></p><hr><h3 id="protocol" tabindex="-1">protocol <a class="header-anchor" href="#protocol" aria-label="Permalink to &quot;protocol&quot;">​</a></h3><p>The encryption scheme applied to a specific message on a <a href="#channel">Channel</a>. os384 supports two: <code>Protocol_ECDH</code> (asymmetric, for private 1:1 &quot;whisper&quot; messages using <a href="#ecdh">ECDH</a> key agreement between owner and one visitor) and <code>Protocol_AES_GCM_256</code> (symmetric <a href="#aes-256-gcm">AES-256-GCM</a>, for group messages where all participants share an encryption key). Protocol can be set per message.</p><p><em>Related: <a href="#e2e-encryption-end-to-end-encryption">E2E Encryption</a>, <a href="#ecdh">ECDH</a>, <a href="#aes-256-gcm">AES-256-GCM</a></em></p>',21)),a("p",null,[a("em",null,[e[50]||(e[50]=t("API: ",-1)),n(r,{type:"enumeration",name:"SBProtocol"})])]),e[97]||(e[97]=a("hr",null,null,-1)),e[98]||(e[98]=a("h3",{id:"public-key-pair",tabindex:"-1"},[t("Public Key Pair "),a("a",{class:"header-anchor",href:"#public-key-pair","aria-label":'Permalink to "Public Key Pair"'},"​")],-1)),e[99]||(e[99]=a("p",null,[t("An asymmetric cryptographic key pair consisting of a private key (kept secret) and a public key (shared freely). In os384, all key pairs use "),a("a",{href:"#p-384"},"P-384"),t(". The public key is used to encrypt data "),a("em",null,"to"),t(" you and verify your digital signatures; the private key is used to decrypt and to sign.")],-1)),a("p",null,[e[51]||(e[51]=t("In os384: key pairs serve double duty — they are both cryptographic credentials and identity. Your ",-1)),e[52]||(e[52]=a("a",{href:"#channel-id"},"Channel ID",-1)),e[53]||(e[53]=t(" is derived from your public key, so identity and encryption capability are mathematically inseparable. For public channel servers, key pairs are generated offline using ",-1)),n(r,{type:"function",name:"sbCrypto.gen_p384_pair"}),e[54]||(e[54]=t(".",-1))]),e[100]||(e[100]=o(`<p><em>Related: <a href="#p-384">P-384</a>, <a href="#owner-key">Owner Key</a>, <a href="#ecdh">ECDH</a></em></p><hr><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><h3 id="ready-template" tabindex="-1">ready template <a class="header-anchor" href="#ready-template" aria-label="Permalink to &quot;ready template&quot;">​</a></h3><p>A construction pattern used throughout lib384. Because many classes require asynchronous initialization (key generation, network lookups, WebSocket setup), they cannot complete setup in a synchronous constructor. Instead, each such class exposes a <code>ready</code> property — a Promise that resolves to the fully initialized object. You create the instance synchronously, then <code>await obj.ready</code> before accessing any properties.</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(handle)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ch.ready          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// waits for key import and channel setup</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;hello world&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// safe to call now</span></span></code></pre></div><p>Accessing key properties (like <code>channelId</code>, <code>userPublicKey</code>) before <code>ready</code> resolves will throw. All classes in the <a href="#sb384">SB384</a> hierarchy follow this pattern.</p><p><em>Related: <a href="#sb384">SB384</a>, <a href="#channel">Channel</a>, <a href="#channel">ChannelSocket</a></em></p><hr><h3 id="restricted" tabindex="-1">Restricted <a class="header-anchor" href="#restricted" aria-label="Permalink to &quot;Restricted&quot;">​</a></h3><p>A channel mode where only <a href="#visitor">Visitors</a> explicitly approved by the <a href="#owner">Owner</a> can participate. When a channel is restricted, the owner distributes encrypted copies of the channel&#39;s shared key to each approved visitor individually, using <a href="#ecdh">ECDH</a> between the owner&#39;s key and each visitor&#39;s key. Restriction is a &quot;fire once&quot; operation — once set, the access model is locked and can only be changed through further owner action.</p><p>In os384: a restricted channel with rotated keys is the strongest privacy mode available — the channel server cannot read messages, and the participant set is entirely under owner control. This is the foundation for <a href="#micro-federation">Micro Federation</a> and the &quot;<a href="#e2e-encryption-end-to-end-encryption">Insider Privacy Model</a>&quot; described in the background documentation.</p><p><em>Related: <a href="#owner">Owner</a>, <a href="#e2e-encryption-end-to-end-encryption">E2E Encryption</a>, <a href="#micro-federation">Micro Federation</a>, <a href="#visitor">Visitor</a></em></p><hr><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><h3 id="salt" tabindex="-1">salt <a class="header-anchor" href="#salt" aria-label="Permalink to &quot;salt&quot;">​</a></h3><p>A random value mixed into data before hashing or key derivation to ensure that identical inputs produce different outputs. Salts prevent precomputed lookup table attacks (&quot;rainbow tables&quot;) and ensure that two users storing identical files produce differently-keyed ciphertexts even though the content hash (h1) is the same.</p><p>In os384: salts are generated by the <a href="#storage-server">Storage Server</a> when a new object is first registered (before encryption), stored alongside the encrypted object, and returned to any client presenting a valid <a href="#fn">FN</a> + <a href="#verification">verification</a> for decryption.</p><p><em>Related: <a href="#nonce">nonce</a>, <a href="#iv">iv</a>, <a href="#pbkdf2">PBKDF2</a>, <a href="#fn">FN</a>, <a href="#aes-256-gcm">AES-256-GCM</a></em></p><hr><h3 id="sb384" tabindex="-1">SB384 <a class="header-anchor" href="#sb384" aria-label="Permalink to &quot;SB384&quot;">​</a></h3><p>The root identity object in lib384 — a <a href="#p-384-secp384r1">P-384</a> key pair with its externally-visible identity formats. Every user, channel, and app key in os384 is ultimately an SB384 object. The class is the &quot;basic capability object&quot;: its <code>userId</code> (a 43-char base62 SHA-384 hash of the public key) is used interchangeably as both a user ID and a channel ID; its <code>userPrivateKey</code> proves ownership.</p><p>Follows the <a href="#ready-template">ready template</a>: always <code>await obj.ready</code> before accessing properties.</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> identity</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SB384</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> identity.ready</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(identity.userId)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// e.g. &quot;Xk4aB3...&quot;  (43 chars)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(identity.userPublicKey) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;PNk4...&quot; + base62-encoded coordinates</span></span></code></pre></div><p>The name traces back to &quot;Snackabra 384&quot; — the project from which os384 evolved. The <code>ChannelKeys</code> and <code>Channel</code> classes extend SB384, adding channel-server connectivity on top of the base key pair.</p><p><em>Related: <a href="#p-384-secp384r1">P-384</a>, <a href="#channel-id">Channel ID</a>, <a href="#owner-key">Owner Key</a>, <a href="#dehydrated-key">dehydrated key</a>, <a href="#ready-template">ready template</a></em></p>`,26)),a("p",null,[a("em",null,[e[55]||(e[55]=t("API: ",-1)),n(r,{type:"class",name:"SB384"})])]),e[101]||(e[101]=o('<hr><h3 id="sbfs-os384-virtual-file-system" tabindex="-1">SBFS (os384 Virtual File System) <a class="header-anchor" href="#sbfs-os384-virtual-file-system" aria-label="Permalink to &quot;SBFS (os384 Virtual File System)&quot;">​</a></h3><p>The virtual file system that the <a href="#loader">Loader</a> constructs in a browser subdomain when launching an app. SBFS uses a browser <a href="#service-worker">Service Worker</a> to intercept all HTTP requests within the app&#39;s origin and serve responses from the decrypted <a href="#fileset">FileSet</a> contents. To the app, it looks like a normal web server; in reality, all files are being decrypted from an encrypted shard and served from memory.</p><p><em>Related: <a href="#loader">Loader</a>, <a href="#fileset">FileSet</a>, <a href="#service-worker">Service Worker</a></em></p>',4)),a("p",null,[a("em",null,[e[56]||(e[56]=t("API: ",-1)),n(r,{type:"class",name:"SBFileSystem"}),e[57]||(e[57]=t(", ",-1)),n(r,{type:"class",name:"SBFileSystem2"})])]),e[102]||(e[102]=o('<hr><h3 id="service-worker" tabindex="-1">Service Worker <a class="header-anchor" href="#service-worker" aria-label="Permalink to &quot;Service Worker&quot;">​</a></h3><p>A browser standard that allows JavaScript code to intercept and handle network requests within a specific origin, running in a background thread separate from the page. os384 uses a Service Worker as the core of <a href="#sbfs">SBFS</a>: once registered in a subdomain, it intercepts every request the app makes and serves the appropriate decrypted file from the <a href="#fileset">FileSet</a> in memory.</p><p>In os384: the Service Worker is what makes os384 apps work transparently — it bridges the gap between the encrypted storage system and the web app&#39;s expectation of a normal file server.</p><p><em>Related: <a href="#sbfs">SBFS</a>, <a href="#loader">Loader</a>, <a href="#fileset">FileSet</a></em></p><hr><h3 id="shard" tabindex="-1">Shard <a class="header-anchor" href="#shard" aria-label="Permalink to &quot;Shard&quot;">​</a></h3><p>The fundamental storage unit in os384. A shard is an immutable, encrypted, content-addressed binary blob stored on a <a href="#storage-server">Storage Server</a>. Shards have no metadata whatsoever — no name, no type, no owner record. All context about a shard (what it contains, who has rights to it, how to decrypt it) exists solely in <a href="#channel">Channel</a> messages that carry the shard&#39;s <a href="#manifest">manifest</a>.</p><p>Accessed by <a href="#fn">FN</a> + <a href="#verification">verification</a> and decrypted using the associated key, <a href="#iv">iv</a>, and <a href="#salt">salt</a>. &quot;Shard&quot; and &quot;<a href="#object">object</a>&quot; refer to the same thing — &quot;object&quot; emphasizes the logical view, &quot;shard&quot; the physical storage unit.</p><p><em>Related: <a href="#object">object</a>, <a href="#fn">FN</a>, <a href="#verification">verification</a>, <a href="#storage-server">Storage Server</a>, <a href="#deduplication">deduplication</a>, <a href="#channel">Channel</a></em></p>',10)),a("p",null,[a("em",null,[e[58]||(e[58]=t("API: ",-1)),n(r,{type:"interface",name:"ShardInfo"}),e[59]||(e[59]=t(", ",-1)),n(r,{type:"interface",name:"ObjectHandle"}),e[60]||(e[60]=t(", ",-1)),n(r,{type:"class",name:"StorageApi"})])]),e[103]||(e[103]=o('<hr><h3 id="sovereignty" tabindex="-1">sovereignty <a class="header-anchor" href="#sovereignty" aria-label="Permalink to &quot;sovereignty&quot;">​</a></h3><p>The combination of three user rights that os384 is designed to guarantee: <strong>control</strong> (you decide who accesses your data and on what terms), <strong>transparency</strong> (you know where and how your data is stored and what laws apply), and <strong>freedom</strong> (you can always export your data and take it elsewhere — no vendor lock-in). This framing synthesizes the User Data Manifesto (Karlitschek, Roy) and related work and is the organizing principle of os384&#39;s design.</p><p>In technical terms, sovereignty is realized through client-side key management, open-source servers, and <a href="#micro-federation">Micro Federation</a>.</p><p><em>Related: <a href="#micro-federation">Micro Federation</a>, <a href="#e2e-encryption-end-to-end-encryption">E2E Encryption</a>, <a href="#restricted">Restricted</a>, <a href="#wallet">Wallet</a>, <a href="#personal-channel-server">Personal Channel Server</a></em></p><p><em>Read more: <a href="/BhoW6b/background.html">background</a></em></p><hr><h3 id="storage-budget" tabindex="-1">Storage Budget <a class="header-anchor" href="#storage-budget" aria-label="Permalink to &quot;Storage Budget&quot;">​</a></h3><p>The amount of storage a <a href="#channel">Channel</a> is authorized to use, measured in <a href="#perma">permas</a> (4 KiB units). All stored <a href="#object">objects</a> are charged against the originating channel&#39;s budget at the time of storage. When the budget is exhausted, the channel enters <a href="#cryptobiosis">cryptobiosis</a>. Budget is transferred between channels via <a href="#budd">budd</a> or <a href="#storage-token">storage tokens</a>.</p><p><em>Related: <a href="#perma">perma</a>, <a href="#budd">budd</a>, <a href="#storage-token">storage token</a>, <a href="#cryptobiosis">cryptobiosis</a></em></p>',10)),a("p",null,[a("em",null,[e[61]||(e[61]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"getCapacity"}),e[62]||(e[62]=t(", ",-1)),n(r,{type:"class",name:"Channel",method:"setCapacity"})])]),e[104]||(e[104]=o('<hr><h3 id="storage-server" tabindex="-1">Storage Server <a class="header-anchor" href="#storage-server" aria-label="Permalink to &quot;Storage Server&quot;">​</a></h3><p>The edge server responsible for storing and retrieving encrypted <a href="#shard">objects (shards)</a>. The storage server handles content-addressed blob storage (<code>storeRequest</code>, <code>storeData</code>, <code>fetchData</code>) and never sees plaintext — all encryption and decryption happens on the client. In the current implementation this is merged with the <a href="#channel-server">Channel Server</a> into a single service, but remains architecturally distinct.</p><p><em>Related: <a href="#shard">Shard</a>, <a href="#channel-server">Channel Server</a>, <a href="#kv_global">KV_global</a>, <a href="#fn">FN</a></em></p><p><em>Read more: <a href="/BhoW6b/storage.html">storage</a></em></p><hr><h3 id="storage-token" tabindex="-1">storage token <a class="header-anchor" href="#storage-token" aria-label="Permalink to &quot;storage token&quot;">​</a></h3><p>A single-use authorization for a specific amount of <a href="#storage-budget">storage budget</a>. Consuming a token (via <code>SB.create(token)</code>) creates a new <a href="#channel">Channel</a> carrying that budget; the token cannot be reused.</p><p>Two ways to obtain a storage token:</p><ul><li><strong><a href="#bootstrap">Bootstrap</a></strong> — insert a token directly into the Channel Server&#39;s KV store using <code>wrangler kv key put</code> or <code>bootstrap.token.ts</code>. Requires server ownership. Used once at initial setup (or to replenish a server).</li><li><strong>Mint</strong> — draw a new token from an existing funded channel using <code>budgetChannel.getStorageToken(size)</code>. Requires a channel with available budget. Used to provision new users or sub-systems.</li></ul><p>Storage tokens are the primary out-of-band mechanism for provisioning users who have no channels yet.</p><p><em>Related: <a href="#storage-budget">Storage Budget</a>, <a href="#ledger_key">LEDGER_KEY</a>, <a href="#budd">budd</a>, <a href="#wallet">Wallet</a>, <a href="#bootstrap">bootstrap</a></em></p>',12)),a("p",null,[a("em",null,[e[63]||(e[63]=t("API: ",-1)),n(r,{type:"interface",name:"SBStorageToken"})])]),e[105]||(e[105]=o('<hr><h3 id="shadow-manifest" tabindex="-1">shadow manifest <a class="header-anchor" href="#shadow-manifest" aria-label="Permalink to &quot;shadow manifest&quot;">​</a></h3><p>A local-only override for an app&#39;s <a href="#manifest">manifest</a> (definition 2), placed as <code>.384.manifest.json</code> (dotfile) in the app&#39;s working directory. <a href="#appmain">AppMain</a> checks for this dotfile first and, if present, uses it in place of <code>384.manifest.json</code>. This lets you iterate on an app&#39;s manifest locally without touching the deployed version or running the full <a href="#loader">Loader</a> and service worker stack.</p><p>The shadow manifest is a development convenience only — it should be gitignored and never deployed. It is the primary bridge for developing os384 apps against a local wrangler server stack without needing the browser Loader infrastructure.</p><p><em>Related: <a href="#manifest">manifest</a>, <a href="#appmain">AppMain</a>, <a href="#loader">Loader</a></em></p><p><em>Read more: <a href="/BhoW6b/dev/local-stack.html">dev/local-stack</a></em></p><hr><h3 id="strongpin" tabindex="-1">strongpin <a class="header-anchor" href="#strongpin" aria-label="Permalink to &quot;strongpin&quot;">​</a></h3><p>A compact, human-typeable identifier used as the &quot;username&quot; component of <a href="#wallet">Wallet</a> authentication. A strongpin consists of one or more 4-character groups from a carefully designed character set that excludes visually ambiguous characters (e.g., <code>0</code> vs <code>O</code>) and avoids common words. Each 4-character group provides 19 bits of entropy; a full 16-character (4-group) strongpin provides 76 bits.</p><p>In os384: a strongpin is paired with a passphrase and fed into <a href="#pbkdf2">PBKDF2</a> to derive the wallet&#39;s key material. The character set is designed for dictation and reliable entry on mobile keyboards.</p><p><em>Related: <a href="#wallet">Wallet</a>, <a href="#vault">Vault</a>, <a href="#pbkdf2">PBKDF2</a></em></p><p><em>Read more: <a href="/BhoW6b/strongpin.html">strongpin</a></em></p><hr><h3 id="subchannel" tabindex="-1">SubChannel <a class="header-anchor" href="#subchannel" aria-label="Permalink to &quot;SubChannel&quot;">​</a></h3><p>A 4-character tag that scopes messages within a <a href="#channel">Channel</a>, providing logical partitioning of the message stream without creating separate channels. Every message <code>_id</code> includes a subChannel field. Used internally by os384 for TTL-categorized storage (TTL messages are duplicated into sub-channels <code>___3</code> through <code>___8</code> for efficient range queries).</p><p><em>Related: <a href="#channel">Channel</a>, <a href="#message">Message</a>, <a href="#ttl">TTL</a></em></p>',16)),a("p",null,[a("em",null,[e[64]||(e[64]=t("API: ",-1)),n(r,{type:"interface",name:"MessageOptions"})])]),e[106]||(e[106]=o('<hr><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><h3 id="timestamp-prefix" tabindex="-1">timestamp prefix <a class="header-anchor" href="#timestamp-prefix" aria-label="Permalink to &quot;timestamp prefix&quot;">​</a></h3><p>A 26-character base-4 string embedded in every <a href="#message">message&#39;s</a> <code>_id</code>. Encodes the server-assigned timestamp in a format that sorts lexicographically in chronological order, enabling efficient prefix-based range queries on the message log without a secondary index. Base-4 (digits 0–3) was chosen because it maps cleanly into the key format and supports the branching factor of the <a href="#deep-history">deep history</a> tree.</p><p><em>Related: <a href="#message">Message</a>, <a href="#deep-history">deep history</a>, <a href="#channel">Channel</a></em></p><hr><h3 id="ttl-time-to-live" tabindex="-1">TTL (Time to Live) <a class="header-anchor" href="#ttl-time-to-live" aria-label="Permalink to &quot;TTL (Time to Live)&quot;">​</a></h3><p>The lifetime setting for a message or shard, encoded as an index rather than a raw duration. Valid values and their meanings:</p><table tabindex="0"><thead><tr><th>Index</th><th>Duration</th></tr></thead><tbody><tr><td>0</td><td>Ephemeral (never stored)</td></tr><tr><td>3</td><td>1 minute</td></tr><tr><td>4</td><td>5 minutes</td></tr><tr><td>5</td><td>30 minutes</td></tr><tr><td>6</td><td>4 hours</td></tr><tr><td>7</td><td>36 hours</td></tr><tr><td>8</td><td>10 days</td></tr><tr><td>15</td><td>Permanent (default)</td></tr></tbody></table><p>Values 1–2 and 9–14 are reserved. TTL=15 (permanent/permastore) is the default — messages and shards are stored forever unless explicitly set otherwise. Routable messages (with a <code>sendTo</code> field) may not have TTL above 8.</p><p><em>Related: <a href="#cryptobiosis">cryptobiosis</a>, <a href="#deep-history">deep history</a>, <a href="#message">Message</a>, <a href="#subchannel">SubChannel</a></em></p>',11)),a("p",null,[a("em",null,[e[65]||(e[65]=t("API: ",-1)),n(r,{type:"type-alias",name:"MessageTtl"})])]),e[107]||(e[107]=o('<hr><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><h3 id="vault" tabindex="-1">Vault <a class="header-anchor" href="#vault" aria-label="Permalink to &quot;Vault&quot;">​</a></h3><p>A <a href="#wallet">Wallet</a> that has been registered with and authorized on a <a href="#channel-server">Channel Server</a>. While a Wallet is a purely local, offline construct (it can exist as an exported key file), a Vault is live — it has a corresponding channel on a server, enabling remote access, key backup, and the ability to restore from a <a href="#strongpin">strongpin</a> and passphrase on a new device.</p><p><em>Related: <a href="#wallet">Wallet</a>, <a href="#strongpin">strongpin</a>, <a href="#channel">Channel</a>, <a href="#loader">Loader</a></em></p><hr><h3 id="verification" tabindex="-1">verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;verification&quot;">​</a></h3><p>A server-generated random value (stored as a dot-separated string of four 16-bit integers; effectively 64 bits of randomness) returned when an <a href="#object">object</a> is first stored. Subsequently, presenting the <a href="#fn">FN</a> together with the correct verification is required to retrieve the object.</p><p>The verification serves two purposes: it proves that you (or someone you authorized) previously paid for the storage of this object; and it prevents enumeration attacks — an attacker cannot retrieve objects by guessing FNs alone.</p><p><em>Related: <a href="#fn">FN</a>, <a href="#object">object</a>, <a href="#shard">Shard</a>, <a href="#manifest">manifest</a></em></p>',10)),a("p",null,[a("em",null,[e[66]||(e[66]=t("API: ",-1)),n(r,{type:"interface",name:"ObjectHandle"}),e[67]||(e[67]=t(", ",-1)),n(r,{type:"interface",name:"ShardInfo"})])]),e[108]||(e[108]=o('<hr><h3 id="visitor" tabindex="-1">Visitor <a class="header-anchor" href="#visitor" aria-label="Permalink to &quot;Visitor&quot;">​</a></h3><p>A non-owner participant in a <a href="#channel">Channel</a>. Visitors can send and receive messages (subject to the channel&#39;s <a href="#restricted">restriction</a> settings) but cannot perform administrative operations. In a <a href="#restricted">restricted</a> channel, visitors must be explicitly approved by the <a href="#owner">Owner</a>. The public keys of all current visitors are stored in the channel&#39;s <a href="#kv_local">KV_local</a>.</p><p><em>Related: <a href="#owner">Owner</a>, <a href="#restricted">Restricted</a>, <a href="#channel">Channel</a></em></p>',4)),a("p",null,[a("em",null,[e[68]||(e[68]=t("API: ",-1)),n(r,{type:"class",name:"Channel",method:"acceptVisitor"}),e[69]||(e[69]=t(", ",-1)),n(r,{type:"class",name:"Channel",method:"getPubKeys"})])]),e[109]||(e[109]=o('<hr><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><h3 id="wallet" tabindex="-1">Wallet <a class="header-anchor" href="#wallet" aria-label="Permalink to &quot;Wallet&quot;">​</a></h3><p>A local, offline representation of a user&#39;s cryptographic identity in os384. A Wallet holds the key material derived from a <a href="#strongpin">strongpin</a> + passphrase via <a href="#pbkdf2">PBKDF2</a>, which is used to access channels and storage. A Wallet that has been instantiated on a server is called a <a href="#vault">Vault</a>. Wallets can be exported as key files for backup or migration between devices.</p><p><em>Related: <a href="#vault">Vault</a>, <a href="#strongpin">strongpin</a>, <a href="#pbkdf2">PBKDF2</a>, <a href="#channel">Channel</a>, <a href="#local-storage">Local Storage</a></em></p><p><em>Read more: <a href="/BhoW6b/wallet.html">wallet</a></em></p><hr><h3 id="whisper" tabindex="-1">whisper <a class="header-anchor" href="#whisper" aria-label="Permalink to &quot;whisper&quot;">​</a></h3><p>The informal name for <code>Protocol_ECDH</code>, the default 1:1 message encryption protocol in os384. When a message is sent with a <code>sendTo</code> field specifying a recipient, it is &quot;whispered&quot; — encrypted using a shared secret derived from <a href="#ecdh-elliptic-curve-diffie-hellman">ECDH</a> key agreement between the sender&#39;s channel key and the recipient&#39;s <a href="#p-384-secp384r1">P-384</a> public key. Only the intended recipient can decrypt it.</p><p>Contrast with <code>Protocol_AES_GCM_256</code>, which uses a shared passphrase for group channels where all participants hold the same key.</p><p>In os384: whisper is the default when you call <code>channel.send(contents, { sendTo: recipientId })</code>. Without <code>sendTo</code>, messages are encrypted for the channel owner instead.</p><p><em>Related: <a href="#ecdh-elliptic-curve-diffie-hellman">ECDH</a>, <a href="#e2e-encryption-end-to-end-encryption">E2E Encryption</a>, <a href="#protocol">protocol</a>, <a href="#message">Message</a></em></p>',12)),a("p",null,[a("em",null,[e[70]||(e[70]=t("API: ",-1)),n(r,{type:"class",name:"Protocol_ECDH"})])])])}const v=s(l,[["render",c]]);export{g as __pageData,v as default};
